code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] x = new int[n];
            int[] y = new int[n];
            for (int i = 0; i < n; i++) {
                x[i] = sc.nextInt();
                y[i] = sc.nextInt();
            }
            long maxArea = 0;
            for (int i = 0; i < n; i++) {
                for (int j = i + 1; j < n; j++) {
                    for (int k = j + 1; k < n; k++) {
                        long area = Math.abs((x[i]*(y[j]-y[k]) + x[j]*(y[k]-y[i]) + x[k]*(y[i]-y[j])) / 2);
                        maxArea = Math.max(maxArea, area);
                    }
                }
            }
            System.out.println(maxArea * 2);
        }
    }
}

code.JavaScript:
const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const n = parseInt(readline());
    const points = readline().split(' ').map(Number);
    const x = points.filter((_, i) => i % 2 === 0);
    const y = points.filter((_, i) => i % 2 === 1);
    let maxArea = 0;
    for (let j = 0; j < n; j++) {
        for (let k = j + 1; k < n; k++) {
            for (let l = k + 1; l < n; l++) {
                const area = Math.abs((x[j]*(y[k]-y[l]) + x[k]*(y[l]-y[j]) + x[l]*(y[j]-y[k])) / 2);
                maxArea = Math.max(maxArea, area);
            }
        }
    }
    console.log(maxArea * 2);
}

